import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Visitor {
  id: string;
  name: string;
  email: string;
  phone: string;
  organization?: string;
  visitorNumber: number;
  isWinner: boolean;
  timestamp: string;
}

export enum AppView {
  WELCOME = 'welcome',
  FORM = 'form',
  RESULT = 'result',
  ADMIN = 'admin'
}

export const COLORS = {
  PRIMARY: '#6c3281',
  SECONDARY: '#d41872',
  ACCENT: '#ffb703',
  SUCCESS: '#4ade80'
};

export const LINKS = {
  ONBOARDING: 'https://alatpay.ng/signup',
  COMMUNITY: 'https://alat.ng/developer-community'
};

export const STORAGE_KEYS = {
  VISITORS: 'alatpay_visitors',
  COUNTER: 'alatpay_visitor_counter'
};

import { GoogleGenAI } from "@google/genai";

export const getPersonalizedMessage = async (name: string, isWinner: boolean, organization?: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const context = organization ? `from ${organization}` : "";

    const prompt = isWinner 
      ? `Write a super enthusiastic, short 1-sentence congratulatory message for ${name} ${context} who just won a prize at the ALATPay tech booth. Keep it fun and fintech-focused.`
      : `Write a friendly, short 1-sentence motivational tech/business tip for ${name} ${context} visiting the ALATPay booth. Use an encouraging tone.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || "Thank you for visiting ALATPay!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return isWinner 
      ? `🎉 Congratulations ${name}! You're one of our lucky winners!`
      : `Thanks for stopping by, ${name}! Stay tuned for more opportunities.`;
  }
};

import React, { useEffect, useRef } from 'react';

const Confetti: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const pieces: {
      x: number;
      y: number;
      size: number;
      color: string;
      speed: number;
      angle: number;
      rotation: number;
    }[] = [];

    const colors = ['#6c3281', '#d41872', '#ffb703', '#4ade80', '#3b82f6'];

    for (let i = 0; i < 150; i++) {
      pieces.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height - canvas.height,
        size: Math.random() * 10 + 5,
        color: colors[Math.floor(Math.random() * colors.length)],
        speed: Math.random() * 3 + 2,
        angle: Math.random() * Math.PI * 2,
        rotation: Math.random() * 0.2 - 0.1
      });
    }

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      pieces.forEach((p) => {
        p.y += p.speed;
        p.x += Math.sin(p.angle) * 2;
        p.angle += 0.1;

        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size / 2, 0, Math.PI * 2);
        ctx.fill();

        if (p.y > canvas.height) {
          p.y = -20;
          p.x = Math.random() * canvas.width;
        }
      });
      requestAnimationFrame(animate);
    };

    animate();

    const handleResize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 pointer-events-none z-50" />;
};

export default Confetti;

import React, { useState, useEffect } from 'react';
import { AppView, Visitor } from './types';
import { STORAGE_KEYS } from './constants';
import WelcomeScreen from './components/WelcomeScreen';
import SignupForm from './components/SignupForm';
import ResultScreen from './components/ResultScreen';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.WELCOME);
  const [visitors, setVisitors] = useState<Visitor[]>([]);
  const [currentVisitor, setCurrentVisitor] = useState<Visitor | null>(null);

  // Persistence logic
  useEffect(() => {
    const storedVisitors = localStorage.getItem(STORAGE_KEYS.VISITORS);
    if (storedVisitors) {
      setVisitors(JSON.parse(storedVisitors));
    }

    // Check for admin view via hash
    const handleHashChange = () => {
      if (window.location.hash === '#admin') {
        setView(AppView.ADMIN);
      } else if (view === AppView.ADMIN) {
        setView(AppView.WELCOME);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange(); // Initial check

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const handleAddVisitor = (visitorData: Omit<Visitor, 'id' | 'visitorNumber' | 'isWinner' | 'timestamp'>) => {
    const nextNumber = visitors.length + 1;
    const isWinner = nextNumber % 2 !== 0; // Odd numbers win

    const newVisitor: Visitor = {
      ...visitorData,
      id: crypto.randomUUID(),
      visitorNumber: nextNumber,
      isWinner,
      timestamp: new Date().toISOString()
    };

    const updatedVisitors = [...visitors, newVisitor];
    setVisitors(updatedVisitors);
    localStorage.setItem(STORAGE_KEYS.VISITORS, JSON.stringify(updatedVisitors));
    setCurrentVisitor(newVisitor);
    setView(AppView.RESULT);
  };

  const resetCounter = () => {
    if (window.confirm("Are you sure you want to reset all data? This cannot be undone.")) {
      setVisitors([]);
      localStorage.removeItem(STORAGE_KEYS.VISITORS);
    }
  };

  return (
    <div className="min-h-screen relative flex flex-col items-center justify-center p-4">
      {/* Background Orbs */}
      <div className="fixed top-0 -left-20 w-72 h-72 bg-purple-400 rounded-full blur-3xl opacity-20 pointer-events-none"></div>
      <div className="fixed bottom-0 -right-20 w-72 h-72 bg-pink-400 rounded-full blur-3xl opacity-20 pointer-events-none"></div>

      <main className="w-full max-w-md z-10 transition-all duration-500">
        {view === AppView.WELCOME && (
          <WelcomeScreen onStart={() => setView(AppView.FORM)} />
        )}

        {view === AppView.FORM && (
          <SignupForm onSubmit={handleAddVisitor} />
        )}

        {view === AppView.RESULT && currentVisitor && (
          <ResultScreen visitor={currentVisitor} onReset={() => setView(AppView.WELCOME)} />
        )}

        {view === AppView.ADMIN && (
          <AdminDashboard visitors={visitors} onReset={resetCounter} />
        )}
      </main>

      {/* Footer Branding */}
      <footer className="fixed bottom-4 text-xs text-purple-900/40 font-medium">
        Powered by ALATPay
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Visitor } from '../types';

interface SignupFormProps {
  onSubmit: (data: Omit<Visitor, 'id' | 'visitorNumber' | 'isWinner' | 'timestamp'>) => void;
}

const SignupForm: React.FC<SignupFormProps> = ({ onSubmit }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    organization: ''
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) newErrors.name = 'Full name is required';
    if (!formData.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) newErrors.email = 'Valid email required';
    if (!formData.phone.match(/^\+?[\d\s-]{10,}$/)) newErrors.phone = 'Valid phone number required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      setIsSubmitting(true);
      // Simulate slight delay for effect
      setTimeout(() => {
        onSubmit(formData);
        setIsSubmitting(false);
      }, 800);
    }
  };

  return (
    <div className="glass rounded-3xl p-8 shadow-2xl space-y-6 animate-in slide-in-from-bottom-8 duration-500">
      <div className="text-center space-y-2">
        <h2 className="text-2xl font-bold text-[#6c3281]">Check Your Luck 🎁</h2>
        <p className="text-sm text-gray-500 italic">Every odd visitor wins a prize!</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-1">
          <label className="text-xs font-bold text-gray-500 uppercase ml-1">Full Name *</label>
          <input
            type="text"
            placeholder="John Doe"
            required
            className={`w-full p-4 bg-gray-50 border-2 rounded-xl focus:ring-2 focus:ring-[#6c3281] outline-none transition-all ${errors.name ? 'border-red-400' : 'border-gray-100'}`}
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
          {errors.name && <p className="text-[10px] text-red-500 ml-1 font-bold">{errors.name}</p>}
        </div>

        <div className="space-y-1">
          <label className="text-xs font-bold text-gray-500 uppercase ml-1">Email Address *</label>
          <input
            type="email"
            placeholder="john@example.com"
            required
            className={`w-full p-4 bg-gray-50 border-2 rounded-xl focus:ring-2 focus:ring-[#6c3281] outline-none transition-all ${errors.email ? 'border-red-400' : 'border-gray-100'}`}
            value={formData.email}
            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
          />
          {errors.email && <p className="text-[10px] text-red-500 ml-1 font-bold">{errors.email}</p>}
        </div>

        <div className="space-y-1">
          <label className="text-xs font-bold text-gray-500 uppercase ml-1">Phone Number *</label>
          <input
            type="tel"
            placeholder="0801 234 5678"
            required
            className={`w-full p-4 bg-gray-50 border-2 rounded-xl focus:ring-2 focus:ring-[#6c3281] outline-none transition-all ${errors.phone ? 'border-red-400' : 'border-gray-100'}`}
            value={formData.phone}
            onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
          />
          {errors.phone && <p className="text-[10px] text-red-500 ml-1 font-bold">{errors.phone}</p>}
        </div>

        <div className="space-y-1">
          <label className="text-xs font-bold text-gray-500 uppercase ml-1">Organization (Optional)</label>
          <input
            type="text"
            placeholder="Your Company Name"
            className="w-full p-4 bg-gray-50 border-2 border-gray-100 rounded-xl focus:ring-2 focus:ring-[#6c3281] outline-none transition-all"
            value={formData.organization}
            onChange={(e) => setFormData({ ...formData, organization: e.target.value })}
          />
        </div>

        <button
          type="submit"
          disabled={isSubmitting}
          className={`w-full py-4 mt-4 bg-gradient-to-r from-[#6c3281] to-[#d41872] text-white rounded-xl font-bold text-lg shadow-xl hover:shadow-2xl transition-all flex items-center justify-center gap-3 ${isSubmitting ? 'opacity-70 cursor-not-allowed' : 'hover:scale-[1.02] active:scale-95'}`}
        >
          {isSubmitting ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Processing...
            </>
          ) : (
            <>
              Check My Luck 🎁
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default SignupForm;

import React, { useEffect, useState } from 'react';
