/**
 * Fetches all leads from the Central Hub (Google Sheets).
 * Requires the Google Apps Script to handle doGet requests.
 */
export const fetchAllLeads = async (): Promise<Visitor[]> => {
  if (!WEBHOOK_URL) return [];

  try {
    const response = await fetch(`${WEBHOOK_URL}?action=getVisitors`);
    if (!response.ok) throw new Error('Failed to fetch global data');
    const data = await response.json();
    return Array.isArray(data) ? data : [];
  } catch (error) {
    console.error("Failed to sync global data:", error);
    return [];
  }
};

import React, { useEffect, useState, useMemo } from 'react';
import { Visitor } from '../types';
import { fetchAllLeads } from '../services/submissionService';

interface AdminDashboardProps {
  visitors: Visitor[];
  onReset: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ visitors: localVisitors, onReset }) => {
  const [globalVisitors, setGlobalVisitors] = useState<Visitor[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSynced, setLastSynced] = useState<Date | null>(null);

  const syncGlobalData = async () => {
    setIsSyncing(true);
    try {
      const data = await fetchAllLeads();
      if (data && data.length > 0) {
        setGlobalVisitors(data);
        setLastSynced(new Date());
      }
    } catch (err) {
      console.error("Sync error", err);
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    syncGlobalData();
  }, []);

  // Merge local and global visitors, removing duplicates based on ID
  const allVisitors = useMemo(() => {
    const map = new Map<string, Visitor>();
    // Global data takes priority as it is the "source of truth"
    globalVisitors.forEach(v => map.set(v.id, v));
    // Local data fills in any gaps (e.g., if just submitted)
    localVisitors.forEach(v => {
      if (!map.has(v.id)) map.set(v.id, v);
    });

    return Array.from(map.values()).sort((a, b) => 
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }, [localVisitors, globalVisitors]);

  const exportToCSV = () => {
    const headers = ['Visitor #', 'Name', 'Email', 'Phone', 'Org', 'Winner', 'Timestamp'];
    const rows = allVisitors.map(v => [
      v.visitorNumber,
      `"${v.name}"`,
      v.email,
      v.phone,
      `"${v.organization || 'N/A'}"`,
      v.isWinner ? 'Yes' : 'No',
      v.timestamp
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(r => r.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `alatpay_global_leads_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const winnersCount = allVisitors.filter(v => v.isWinner).length;

  return (
    <div className="glass rounded-3xl p-8 shadow-2xl space-y-8 animate-in slide-in-from-top-8 duration-500 max-w-2xl mx-auto w-full">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="text-center md:text-left">
          <h2 className="text-2xl font-black text-[#be0b27] flex items-center gap-2">
            Booth Dashboard
            {isSyncing && (
              <svg className="animate-spin h-5 w-5 text-red-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
          </h2>
          <div className="flex items-center gap-2 mt-1 justify-center md:justify-start">
            <span className="text-xs text-gray-500 font-medium">Global Sync:</span>
            <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${lastSynced ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
              {lastSynced ? `Updated ${lastSynced.toLocaleTimeString()}` : 'Not synced'}
            </span>
          </div>
        </div>

        <div className="flex gap-2 w-full md:w-auto">
          <button
            onClick={syncGlobalData}
            disabled={isSyncing}
            className="flex-1 md:flex-none px-4 py-2 bg-gray-100 text-gray-700 rounded-lg text-sm font-bold hover:bg-gray-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 ${isSyncing ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
            Refresh
          </button>
          <button
            onClick={exportToCSV}
            className="flex-1 md:flex-none px-4 py-2 bg-[#be0b27] text-white rounded-lg text-sm font-bold shadow-md hover:bg-[#92091d] transition-colors flex items-center justify-center gap-2"
          >
            Export Global CSV
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
